-- PlayNest initial schema. Run with `supabase db push`.
create extension if not exists pgcrypto;
create type public.user_role as enum ('parent','admin'); create type public.verification_status as enum ('pending','email_verified'); create type public.age_band as enum ('0–2','3–5','6–8','9–12','13+'); create type public.event_request_status as enum ('pending','accepted','declined','waitlisted','cancelled','place_offered','expired'); create type public.event_status as enum ('draft','published','cancelled','completed'); create type public.report_status as enum ('open','reviewing','resolved','dismissed');
create table public.localities(id uuid primary key default gen_random_uuid(),name text not null,city text not null,country_code char(2) not null,timezone text not null default 'Europe/Stockholm',status text not null default 'active' check(status in('active','planned','disabled')),created_at timestamptz not null default now(),unique(name,city));
create table public.profiles(id uuid primary key references auth.users on delete cascade,first_name text not null check(length(first_name) between 1 and 60),avatar_url text,bio text check(length(bio)<=280),languages text[] not null default '{}',primary_locality_id uuid references public.localities,adult_confirmed boolean not null default false,terms_accepted_at timestamptz,privacy_accepted_at timestamptz,safety_accepted_at timestamptz,verification_status public.verification_status not null default 'pending',community_vouched_at timestamptz,role public.user_role not null default 'parent',suspended_at timestamptz,created_at timestamptz not null default now(),updated_at timestamptz not null default now());
create table public.children(id uuid primary key default gen_random_uuid(),parent_id uuid not null references public.profiles on delete cascade,nickname text not null check(length(nickname) between 1 and 50),age_band public.age_band not null,interests text[] not null default '{}',participation_notes text check(length(participation_notes)<=500),created_at timestamptz not null default now(),updated_at timestamptz not null default now());
create table public.venues(id uuid primary key default gen_random_uuid(),locality_id uuid not null references public.localities,name text not null,address_text text not null check(address_text!~*'(door[[:space:]]*code|apartment|floor[[:space:]]*[0-9])'),venue_type text not null,is_public boolean not null default true check(is_public),approval_status text not null default 'pending' check(approval_status in('pending','approved','rejected')),directions_url text,created_by uuid references public.profiles,created_at timestamptz not null default now());
create table public.events(id uuid primary key default gen_random_uuid(),organizer_id uuid references public.profiles on delete cascade,locality_id uuid not null references public.localities,venue_id uuid references public.venues,title text not null check(length(title) between 4 and 100),description text not null check(length(description) between 20 and 1500),category text not null,starts_at timestamptz not null,ends_at timestamptz not null check(ends_at>starts_at),timezone text not null default 'Europe/Stockholm',age_bands public.age_band[] not null,max_children smallint not null check(max_children between 1 and 50),max_adults smallint check(max_adults between 1 and 100),siblings_allowed boolean not null default true,guardian_required boolean not null default true check(guardian_required),environment text not null check(environment in('indoor','outdoor','both')),languages text[] not null default '{}',accessibility_notes text,bring_notes text,cancellation_deadline timestamptz,approval_mode text not null default 'manual' check(approval_mode in('manual','automatic')),registration_status text not null default 'open' check(registration_status in('open','closed')),status public.event_status not null default 'draft',is_example boolean not null default false,completed_at timestamptz,created_at timestamptz not null default now(),updated_at timestamptz not null default now(),check(not is_example or status='completed'),check((status='completed')=(completed_at is not null)));
create table public.event_requests(id uuid primary key default gen_random_uuid(),event_id uuid not null references public.events on delete cascade,requester_id uuid not null references public.profiles on delete cascade,status public.event_request_status not null default 'pending',child_count smallint not null check(child_count between 1 and 20),adult_count smallint not null check(adult_count between 1 and 20),message text check(length(message)<=500),organizer_note text check(length(organizer_note)<=500),place_offer_expires_at timestamptz,created_at timestamptz not null default now(),updated_at timestamptz not null default now(),unique(event_id,requester_id));
create table public.event_request_children(event_request_id uuid references public.event_requests on delete cascade,child_id uuid references public.children on delete cascade,primary key(event_request_id,child_id));
create table public.event_updates(id uuid primary key default gen_random_uuid(),event_id uuid not null references public.events on delete cascade,author_id uuid not null references public.profiles,message text not null check(length(message) between 1 and 500),update_type text not null check(update_type in('general','venue_changed','delayed','cancelled')),created_at timestamptz not null default now());
create table public.attendance_confirmations(id uuid primary key default gen_random_uuid(),event_id uuid not null references public.events on delete cascade,user_id uuid not null references public.profiles on delete cascade,attended boolean not null,confirmed_at timestamptz not null default now(),unique(event_id,user_id));
create table public.interest_checks(id uuid primary key default gen_random_uuid(),creator_id uuid not null references public.profiles,locality_id uuid not null references public.localities,title text not null,description text,category text not null,age_bands public.age_band[] not null,suggested_area text,status text not null default 'open' check(status in('open','converted','closed')),created_at timestamptz not null default now());
create table public.interest_options(id uuid primary key default gen_random_uuid(),interest_check_id uuid not null references public.interest_checks on delete cascade,starts_at timestamptz not null);
create table public.interest_responses(id uuid primary key default gen_random_uuid(),interest_check_id uuid not null references public.interest_checks on delete cascade,user_id uuid not null references public.profiles on delete cascade,interest_option_id uuid references public.interest_options on delete cascade,willing_to_host boolean not null default false,created_at timestamptz not null default now(),unique(interest_check_id,user_id));
create table public.notifications(id uuid primary key default gen_random_uuid(),user_id uuid not null references public.profiles on delete cascade,type text not null,title text not null,body text not null,action_url text,read_at timestamptz,created_at timestamptz not null default now());
create table public.reports(id uuid primary key default gen_random_uuid(),reporter_id uuid not null references public.profiles,reported_user_id uuid references public.profiles,event_id uuid references public.events,reason text not null,details text,status public.report_status not null default 'open',assigned_admin_id uuid references public.profiles,resolution_notes text,created_at timestamptz not null default now(),resolved_at timestamptz,check(reported_user_id is not null or event_id is not null));
create table public.blocks(blocker_id uuid references public.profiles on delete cascade,blocked_user_id uuid references public.profiles on delete cascade,created_at timestamptz not null default now(),primary key(blocker_id,blocked_user_id),check(blocker_id<>blocked_user_id));
create table public.analytics_events(id bigint generated always as identity primary key,user_id uuid references public.profiles on delete set null,event_name text not null,locality_id uuid references public.localities,related_event_id uuid references public.events on delete set null,properties jsonb not null default '{}',created_at timestamptz not null default now(),check(not(properties ?| array['child_name','nickname','participation_notes','email','address'])));
create table public.moderation_audit_log(id bigint generated always as identity primary key,admin_id uuid not null references public.profiles,action text not null,target_type text not null,target_id uuid not null,reason text not null,created_at timestamptz not null default now());
create index events_feed_idx on public.events(locality_id,status,starts_at) where status='published'; create index requests_event_status_idx on public.event_requests(event_id,status); create index notifications_user_idx on public.notifications(user_id,created_at desc); create index reports_status_idx on public.reports(status,created_at); create index analytics_name_time_idx on public.analytics_events(event_name,created_at);
create function public.is_admin() returns boolean language sql stable security definer set search_path='' as $$select exists(select 1 from public.profiles where id=auth.uid() and role='admin' and suspended_at is null)$$;
create function public.is_active_parent() returns boolean language sql stable security definer set search_path='' as $$select exists(select 1 from public.profiles where id=auth.uid() and adult_confirmed and verification_status='email_verified' and suspended_at is null)$$;
alter table public.localities enable row level security;alter table public.profiles enable row level security;alter table public.children enable row level security;alter table public.venues enable row level security;alter table public.events enable row level security;alter table public.event_requests enable row level security;alter table public.event_request_children enable row level security;alter table public.event_updates enable row level security;alter table public.attendance_confirmations enable row level security;alter table public.interest_checks enable row level security;alter table public.interest_options enable row level security;alter table public.interest_responses enable row level security;alter table public.notifications enable row level security;alter table public.reports enable row level security;alter table public.blocks enable row level security;alter table public.analytics_events enable row level security;alter table public.moderation_audit_log enable row level security;
create policy "localities public read" on public.localities for select using(status in('active','planned'));create policy "admins manage localities" on public.localities for all using(public.is_admin()) with check(public.is_admin());
create policy "profile self read" on public.profiles for select using(id=auth.uid() or public.is_admin());create policy "organizer names to active parents" on public.profiles for select using(public.is_active_parent());create policy "profile self insert" on public.profiles for insert with check(id=auth.uid() and adult_confirmed);create policy "profile self update" on public.profiles for update using(id=auth.uid()) with check(id=auth.uid());
create policy "children parent only" on public.children for all using(parent_id=auth.uid() or public.is_admin()) with check(parent_id=auth.uid() or public.is_admin());
create policy "public venue read" on public.venues for select using(is_public or created_by=auth.uid() or public.is_admin());create policy "active parents add venues" on public.venues for insert with check(created_by=auth.uid() and public.is_active_parent() and is_public);
create policy "safe event public read" on public.events for select using((status in('published','completed') and (not is_example or status='completed')) or organizer_id=auth.uid() or public.is_admin());create policy "organizer creates event" on public.events for insert with check(organizer_id=auth.uid() and public.is_active_parent() and guardian_required and not is_example);create policy "organizer updates event" on public.events for update using(organizer_id=auth.uid() or public.is_admin()) with check(organizer_id=auth.uid() or public.is_admin());
create policy "request parties read" on public.event_requests for select using(requester_id=auth.uid() or exists(select 1 from public.events e where e.id=event_id and e.organizer_id=auth.uid()) or public.is_admin());create policy "parent requests" on public.event_requests for insert with check(requester_id=auth.uid() and public.is_active_parent() and status in('pending','waitlisted'));create policy "requester cancels" on public.event_requests for update using(requester_id=auth.uid()) with check(requester_id=auth.uid() and status='cancelled');
create policy "request children parties read" on public.event_request_children for select using(exists(select 1 from public.event_requests r join public.events e on e.id=r.event_id where r.id=event_request_id and(r.requester_id=auth.uid() or e.organizer_id=auth.uid())) or public.is_admin());create policy "requester selects own children" on public.event_request_children for insert with check(exists(select 1 from public.event_requests r join public.children c on c.id=child_id where r.id=event_request_id and r.requester_id=auth.uid() and c.parent_id=auth.uid()));
create policy "updates accepted parties" on public.event_updates for select using(exists(select 1 from public.events e where e.id=event_id and(e.organizer_id=auth.uid() or exists(select 1 from public.event_requests r where r.event_id=e.id and r.requester_id=auth.uid() and r.status='accepted'))) or public.is_admin());create policy "organizer posts update" on public.event_updates for insert with check(author_id=auth.uid() and exists(select 1 from public.events e where e.id=event_id and e.organizer_id=auth.uid()));
create policy "own notifications" on public.notifications for select using(user_id=auth.uid() or public.is_admin());create policy "own notification update" on public.notifications for update using(user_id=auth.uid()) with check(user_id=auth.uid());create policy "system notification insert" on public.notifications for insert with check(user_id=auth.uid());
create policy "submit reports" on public.reports for insert with check(reporter_id=auth.uid() and public.is_active_parent());create policy "reporter or admin read" on public.reports for select using(reporter_id=auth.uid() or public.is_admin());create policy "admin updates reports" on public.reports for update using(public.is_admin()) with check(public.is_admin());create policy "own blocks" on public.blocks for all using(blocker_id=auth.uid() or public.is_admin()) with check(blocker_id=auth.uid());
create policy "analytics safe insert" on public.analytics_events for insert with check(user_id is null or user_id=auth.uid());create policy "analytics admin read" on public.analytics_events for select using(public.is_admin());create policy "audit admin read" on public.moderation_audit_log for select using(public.is_admin());create policy "audit admin insert" on public.moderation_audit_log for insert with check(admin_id=auth.uid() and public.is_admin());
-- Remaining collaboration tables are limited to active users involved or admins.
create policy "interest public read" on public.interest_checks for select using(status='open' or creator_id=auth.uid() or public.is_admin());create policy "interest active create" on public.interest_checks for insert with check(creator_id=auth.uid() and public.is_active_parent());create policy "options public read" on public.interest_options for select using(true);create policy "responses own" on public.interest_responses for all using(user_id=auth.uid() or public.is_admin()) with check(user_id=auth.uid());create policy "attendance own" on public.attendance_confirmations for all using(user_id=auth.uid() or public.is_admin()) with check(user_id=auth.uid());
-- Atomic acceptance locks the event, recalculates accepted child capacity, and cannot oversubscribe.
create or replace function public.decide_event_request(p_request_id uuid,p_decision public.event_request_status,p_organizer_note text default null) returns public.event_request_status language plpgsql security definer set search_path='' as $$declare v_request public.event_requests%rowtype;v_event public.events%rowtype;v_used integer;v_status public.event_request_status;begin select * into v_request from public.event_requests where id=p_request_id for update;if not found then raise exception 'Request not found';end if;select * into v_event from public.events where id=v_request.event_id for update;if v_event.organizer_id<>auth.uid() and not public.is_admin() then raise exception 'Not authorized';end if;if v_request.status not in('pending','waitlisted','place_offered') then raise exception 'Request is not actionable';end if;if p_decision not in('accepted','declined','waitlisted','place_offered') then raise exception 'Invalid decision';end if;v_status:=p_decision;if p_decision='accepted' then select coalesce(sum(child_count),0) into v_used from public.event_requests where event_id=v_event.id and status='accepted' and id<>p_request_id;if v_event.registration_status<>'open' or v_used+v_request.child_count>v_event.max_children then v_status:='waitlisted';end if;end if;update public.event_requests set status=v_status,organizer_note=p_organizer_note,place_offer_expires_at=case when v_status='place_offered' then now()+interval '24 hours' else null end,updated_at=now() where id=p_request_id;insert into public.notifications(user_id,type,title,body,action_url) values(v_request.requester_id,'request_'||v_status::text,'Playdate request updated','Your request for '||v_event.title||' is now '||replace(v_status::text,'_',' ')||'.','/activities');return v_status;end$$;revoke all on function public.decide_event_request(uuid,public.event_request_status,text) from public;grant execute on function public.decide_event_request(uuid,public.event_request_status,text) to authenticated;
create or replace function public.next_waitlist_offer(p_event_id uuid) returns uuid language plpgsql security definer set search_path='' as $$declare v_event public.events%rowtype;v_request_id uuid;begin select * into v_event from public.events where id=p_event_id for update;if v_event.organizer_id<>auth.uid() and not public.is_admin() then raise exception 'Not authorized';end if;select id into v_request_id from public.event_requests where event_id=p_event_id and status='waitlisted' order by created_at for update skip locked limit 1;if v_request_id is not null then perform public.decide_event_request(v_request_id,'place_offered',null);end if;return v_request_id;end$$;grant execute on function public.next_waitlist_offer(uuid) to authenticated;
create function public.handle_new_user() returns trigger language plpgsql security definer set search_path='' as $$begin insert into public.profiles(id,first_name) values(new.id,coalesce(new.raw_user_meta_data->>'first_name','New parent')) on conflict do nothing;return new;end$$;create trigger on_auth_user_created after insert on auth.users for each row execute function public.handle_new_user();
